import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/96-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/96-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/96-出使德意志皇帝.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 我听说他在回来的路上遭遇抢劫。但是这里能够收到锡耶纳，甚至罗马的 来信。所以我实在不明白，为什么我没有收到诸位大人的任何回信。而 且，诸位大人经常说，威尼斯人想要剥夺意大利的自由。既然皇帝已经对 他们公开宣战，那他现在看到诸位大人迟迟没有答复，可能会认为诸位大 人所说的只是空话。因此，我必须重申，最重要的是诸位大人要给我答复 和新的授权，并明确说明我应该采取什么行动。如果诸位大人还有意给皇 帝金钱，那么就要给我送来汇票。正如我之前信中所写，汇票可以通过在 罗马的富格尔家族兑现。诸位大人千万不能认为，1月29日信中的指示还 可以发挥作用。因为，如前所述，那只有当皇帝身在特伦特，而且我能清 楚看出皇帝的战事正在顺利推进，才能发挥作用。但是，如果不能提供现 钱的话，皇帝肯定不会接受那样的提议。即使我想在特伦特给他付款，但 没有现钱在手，我就只能给他提供汇票。这样的话，他要兑现这笔钱，至 少需要一个月的时间。因此，诸位大人1月29日信中的指示，实在不能发 挥任何指导作用。 今天是3月7日，皇帝正在因斯布鲁克。3天前教皇特使收到来自宫廷 的消息，说帝国代表们已经同意，把对皇帝的资助期限再延长6个月。对 此，皇帝陛下表示相当满意，并准备送出信件表达他的意思。这就是我们 听到的关于皇帝的全部消息。不过，人们猜测皇帝会在6到8天内来到此 处，然后再前往他认为必要的地方。特伦特大约有9000步兵和骑兵，他 们2天前去到巴科城堡扎营。巴科城堡在罗韦雷的对面，阿迪杰河的另一 边，是从这里去意大利方向的右边，而罗韦雷多就在左边。巴科城堡的守 卫考虑了3天之后决定投降，那时皇帝的部队正在等待火炮的到来。那里 的守备军有40人，现在还是阶下囚。至于军队是否已经前行，则没有听到 任何消息。有人说，部队会开往布伦托尼科城堡(在河的同一边)。也有 人说，部队会前往罗韦雷多，那里的守备军据说是1500个西班牙人。这些 就是我们从那个方向听到的所有消息。至于特雷维桑境内的军队，我们则 没有听到任何消息。除了听说，在一月之内已经有80辆运送火炮的马车，",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolo Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
